# Private functions
  @fn periodTicks(period, resolution)  @ 23-26
  @fn retrig(stream, host, params, ctx)  @ 30-49
      @contract  retrig tiles the host window with evenly-spaced same-pitch fxNotes; every hit is derived  @ 28
      @contract  velocity ramps params.ramp per tile from the host vel, clamped 1..127; detune inherited verbatim  @ 29
  @fn trill(stream, host, params, ctx)  @ 52-73
      @contract  trill alternates host pitch with a note `step` scale-steps away (via ctx.step); every hit derived  @ 51
  @fn playingAt(events, t)  @ 76-85
      -- Notes sounding at logical tick `t`, ascending by realised pitch (semitone*100 + detune cents).
  @fn arpIndex(count, dir, i)  @ 89-97
      -- Which voice of the active set step `i` plays, by direction. updown bounces without
      -- repeating the extremes (span 2*(n-1)); up/down wrap.
  @fn arp(stream, host, params, ctx)  @ 102-122
      @contract  arp samples the sounding notes at each step (period QN), playing one by `dir`  @ 99
      @contract  dir up|down|updown cycles the current active set; an empty active set -> a rest  @ 100
      @contract  hits abut (endppq = next step), clamped to the window; vel/detune from the voice  @ 101
  @fn ostinato(stream, host, params, ctx)  @ 126-147
      @contract  ostinato gates the sounding region notes by a stored pattern -- pattern gives onset/dur/vel, each voice its pitch/detune  @ 124
      @contract  every voice sounding at a gate onset emits (none -> rest); the pattern loops from the window start; no lengthPpq -> inert  @ 125
  @fn vibrato(stream, host, params, ctx)  @ 152-172
      @contract  vibrato -> lane-1 pb-delta breakpoints in cents; sine of depth cents at 1/period QN  @ 149
      @contract  breakpoints at sine extrema, 'slow'-shaped; linear ramp-in over onset QN  @ 150
      @contract  returns to 0 (centre) at window end -- no residual bend on the channel  @ 151
  @fn interval(a, b)  @ 176-178
      -- Cents between two notes' realised pitches. The microtonal offset already rides
      -- in detune, so this is pure note arithmetic -- no temper needed.
  @fn slide(stream, host, params, ctx)  @ 183-213
      @contract  slide glide-in -> lane-1 pb-delta; slur to target over `over` QN; re-centres at end  @ 180
      @contract  target 'next' = interval to next same-lane note; 'fixed' = params.cents; pb-range clamps  @ 181
      @contract  no next note or unison target -> empty delta (channel untouched)  @ 182
  @fn autopan(stream, host, params, ctx)  @ 217-231
      @contract  auto-pan -> cc-delta breakpoints in cc steps; sine of depth steps at 1/period QN  @ 215
      @contract  extrema-only, 'slow'-shaped; anchored 0 at both ends so the channel re-centres  @ 216
  @fn curveAt(points, a)  @ 234-244
      -- Linear-interpolated normalized value at authored ppq `a`; points ascend in ppq, edges clamp flat.
  @fn lfo(stream, host, params, ctx)  @ 249-277
      @contract  lfo tiles a normalized curve at 1/period QN, mapping each val by centre + scale  @ 246
      @contract  emits absolute cc breakpoints (augment onto rest), clamped 0..127; dest cc1, no UI yet  @ 247
      @contract  each cycle stretches the body lengthPpq -> period ticks; both window edges seeded  @ 248
  @fn velPattern(stream, host, params, ctx)  @ 281-298
      @contract  velPattern rewrites stream-note velocities by a pattern; other fields carry verbatim  @ 279
      @contract  pattern steps per distinct onset (a chord shares one step) and cycles; vel clamps 1..127  @ 280

# Public API (generators.*)
  -- Generator registry
  -- Region park predicate + windows
  @api generators.parksNotes(region)  @ 408-414
      -- A region parks its covered chord iff it carries a note-dest kind: the chain's final note stream
      -- stands in for the members (ownership by dest, not mode). A husk (no kinds) parks nothing.
  @api generators.continuousTargets(fx)  @ 418-425
      -- Continuous targets a chain touches: set keyed 'pb' | <cc number>, empty for a pure-note
      -- chain -- phase 5's per-target scopes key off it. see design/interval-dirt.md § phase 5
  @api generators.chainDestType(fx, target)  @ 429-435
      -- The fold mode a chain presents for one continuous target: replace if any stage targeting it
      -- replaces, else augment -- drives cross-chain layering (a later replace wins). see design/note-macros-v2.md § The fx chain
  @api generators.parkWindows(regions)  @ 440-461
      -- The single source for "what 4.5 parks over": a note window for a discrete-replace chord, a cc window
      -- per continuous cc target and a pb window per continuous pb target (both replace or augment).

